// WebGPU 初始化的典型流程
const adapter = await navigator.gpu.requestAdapter({
    powerPreference: 'high-performance'
});

const device = await adapter.requestDevice({
    requiredFeatures: [],
    requiredLimits: {}
});

// 现在可以用 device 创建 GPU 资源了
const buffer = device.createBuffer({
    size: 1024,
    usage: GPUBufferUsage.VERTEX | GPUBufferUsage.COPY_DST
});

// 查询设备能力
const adapter = await navigator.gpu.requestAdapter();

console.log('支持的特性:', [...adapter.features]);
console.log('最大纹理尺寸:', adapter.limits.maxTextureDimension2D);
console.log('最大缓冲大小:', adapter.limits.maxBufferSize);

// 请求特定特性
const device = await adapter.requestDevice({
    requiredFeatures: ['texture-compression-bc'],
    requiredLimits: {
        maxBufferSize: 256 * 1024 * 1024  // 请求 256MB 最大缓冲
    }
});

// 设备丢失处理
device.lost.then((info) => {
    console.error('GPU 设备丢失:', info.message);
    console.error('丢失原因:', info.reason);
    // reason 可以是 'unknown' 或 'destroyed'
    // 需要重新初始化整个渲染管线
    reinitializeRenderer();
});

// 方式一：mappedAtCreation
const vertexBuffer = device.createBuffer({
    size: vertexData.byteLength,
    usage: GPUBufferUsage.VERTEX | GPUBufferUsage.COPY_DST,
    mappedAtCreation: true  // 创建时立即映射
});

// 写入数据（此时 buffer 映射在 CPU 地址空间）
new Float32Array(vertexBuffer.getMappedRange()).set(vertexData);
vertexBuffer.unmap();  // 取消映射，GPU 可以使用了

// 方式二：queue.writeBuffer
const uniformBuffer = device.createBuffer({
    size: 64,  // 一个 4x4 矩阵
    usage: GPUBufferUsage.UNIFORM | GPUBufferUsage.COPY_DST
});

// 每帧更新 Uniform 数据
const matrixData = new Float32Array([...modelViewProjection]);
device.queue.writeBuffer(uniformBuffer, 0, matrixData);

// 从 GPU 读回数据（staging buffer 模式）
const readBuffer = device.createBuffer({
    size: dataSize,
    usage: GPUBufferUsage.MAP_READ | GPUBufferUsage.COPY_DST
});

// 将数据从 GPU 复制到 staging buffer
const encoder = device.createCommandEncoder();
coder.copyBufferToBuffer(gpuBuffer, 0, readBuffer, 0, dataSize);
device.queue.submit([encoder.finish()]);

// 映射读取（异步）
await readBuffer.mapAsync(GPUMapMode.READ);
const result = new Float32Array(readBuffer.getMappedRange());
readBuffer.unmap();

// 创建纹理
const texture = device.createTexture({
    size: { width: 1024, height: 1024 },
    format: 'rgba8unorm',
    usage: GPUTextureUsage.TEXTURE_BINDING | GPUTextureUsage.RENDER_ATTACHMENT,
    mipLevelCount: 5  // 1024 -> 512 -> 256 -> 128 -> 64
});

// 创建 TextureView — 只看第 2 级 mipmap
const view = texture.createView({
    baseMipLevel: 2,
    mipLevelCount: 1  // 只访问 256x256 那一层
});

// 像素风格采样器（最近邻 + 重复）
const pixelSampler = device.createSampler({
    magFilter: 'nearest',
    minFilter: 'nearest',
    mipmapFilter: 'nearest',
    addressModeU: 'repeat',
    addressModeV: 'repeat'
});

// 写实风格采样器（双线性 + 边缘钳制）
const smoothSampler = device.createSampler({
    magFilter: 'linear',
    minFilter: 'linear',
    mipmapFilter: 'linear',
    addressModeU: 'clamp-to-edge',
    addressModeV: 'clamp-to-edge'
});

